function getSvgMarkup(value, fallbackKey = null) {
  const normalize = (input) => String(input || '').trim().toLowerCase();
  const key = normalize(value);
  const fallback = normalize(fallbackKey);

  const keys = Object.keys(LOCAL_SVG_ASSETS);
  const matchKey = keys.find((entry) => normalize(entry) === key);
  if (matchKey) {
    return LOCAL_SVG_ASSETS[matchKey];
  }

  const fallbackMatch = keys.find((entry) => normalize(entry) === fallback);
  if (fallbackMatch) {
    return LOCAL_SVG_ASSETS[fallbackMatch];
  }

  return '';
}

class StageIcon extends BaseComponent {
  static get observedAttributes() {
    return ['state', 'image-state-1', 'image-state-2', 'image-state-3', 'alt'];
  }

  connectedCallback() {
    this.render();
    this.addEventListener('click', this.onTap);
  }

  attributeChangedCallback(name, oldValue, newValue) {
    if (oldValue === newValue) {
      return;
    }

    if (!this.visualElement) {
      this.render();
      return;
    }

    if (name === 'alt') {
      this.applyAltText();
      return;
    }

    this.render();
  }

  get state() {
    const parsed = Number.parseInt(this.getAttribute('state') || '1', 10);
    if (Number.isNaN(parsed)) {
      return 1;
    }

    return Math.min(3, Math.max(1, parsed));
  }

  get altText() {
    return this.getAttribute('alt') || '';
  }

  get currentImageSource() {
    const state = this.state;
    const explicitStateImage = this.getAttribute(`image-state-${state}`);
    if (explicitStateImage) {
      return explicitStateImage;
    }

    const fallback = this.getAttribute('image-state-1');
    return fallback || 'flag-coin';
  }

  applyAltText() {
    if (!this.visualElement) {
      return;
    }

    if (this.visualElement.tagName === 'IMG') {
      this.visualElement.alt = this.altText;
      return;
    }

    const svgElement = this.visualElement.querySelector('svg');
    if (!svgElement) {
      return;
    }

    if (this.altText) {
      svgElement.setAttribute('role', 'img');
      svgElement.setAttribute('aria-label', this.altText);
      svgElement.removeAttribute('aria-hidden');
    } else {
      svgElement.setAttribute('aria-hidden', 'true');
      svgElement.removeAttribute('role');
      svgElement.removeAttribute('aria-label');
    }
  }

  render() {
    this.clear();

    const svgMarkup = getSvgMarkup(this.currentImageSource);
    if (svgMarkup) {
      const wrapper = this.createElement('div', {
        innerHTML: svgMarkup,
        style: {
          display: 'block',
          width: '100%',
          height: 'auto',
          userSelect: 'none',
          WebkitUserSelect: 'none',
          WebkitTouchCallout: 'none',
          pointerEvents: 'none',
          lineHeight: '0'
        }
      });
      const svgElement = wrapper.querySelector('svg');
      if (svgElement) {
        this.setStyles(svgElement, {
          display: 'block',
          width: '100%',
          height: 'auto',
          pointerEvents: 'none'
        });
      }
      this.append(wrapper);
      this.visualElement = wrapper;
    } else {
      const image = this.createElement('img', {
        src: this.currentImageSource,
        alt: this.altText,
        style: {
          display: 'block',
          width: '100%',
          height: 'auto',
          userSelect: 'none',
          WebkitUserSelect: 'none',
          WebkitUserDrag: 'none',
          WebkitTouchCallout: 'none',
          pointerEvents: 'none'
        }
      });
      image.setAttribute('draggable', 'false');
      this.append(image);
      this.visualElement = image;
    }

    this.applyAltText();
    this.setHostStyles({
      display: 'block',
      userSelect: 'none',
      WebkitUserSelect: 'none',
      WebkitTapHighlightColor: 'transparent',
      WebkitTouchCallout: 'none',
      outline: 'none'
    });
  }

  onTap = () => {
    this.dispatchEvent(new CustomEvent('stage-icon-tap', {
      bubbles: true,
      composed: true,
      detail: {
        state: this.state,
        image: this.currentImageSource
      }
    }));
  };

  disconnectedCallback() {
    this.removeEventListener('click', this.onTap);
  }
}

customElements.define('stage-icon', StageIcon);

export default StageIcon;
